"""Main Flask-like web application with error handlers."""
import json
from auth import authenticate_user
from users import get_user, create_user, update_user, delete_user, list_users
from posts import get_post, create_post, update_post, delete_post
from comments import get_comments, add_comment, delete_comment
from middleware import check_rate_limit, log_request
from database import get_db_connection, execute_query, close_connection
from validators import validate_email, validate_username, validate_post_content, validate_comment


class Request:
    """Simple request object."""
    def __init__(self, method, path, body=None, headers=None):
        self.method = method
        self.path = path
        self.body = body or {}
        self.headers = headers or {}


class Response:
    """Simple response object."""
    def __init__(self, body, status_code=200):
        self.body = body
        self.status_code = status_code

    def to_dict(self):
        return {"body": self.body, "status_code": self.status_code}


def handle_request(request):
    """Route and handle an incoming request."""
    try:
        log_request(request)
        check_rate_limit(request)

        if request.path == "/auth":
            token = authenticate_user(request.body.get("username"), request.body.get("password"))
            return Response({"token": token}, 200)

        elif request.path.startswith("/users"):
            return handle_users(request)

        elif request.path.startswith("/posts"):
            return handle_posts(request)

        elif request.path.startswith("/comments"):
            return handle_comments(request)

        else:
            return Response({"error": "Not found"}, 404)

    except Exception as e:
        # Generic error handler — should catch specific types
        return Response({"error": str(e)}, 500)


def handle_users(request):
    """Handle user-related requests."""
    try:
        if request.method == "GET":
            user_id = request.body.get("user_id")
            if user_id:
                user = get_user(user_id)
                return Response({"user": user}, 200)
            else:
                users = list_users()
                return Response({"users": users}, 200)
        elif request.method == "POST":
            user = create_user(request.body)
            return Response({"user": user}, 201)
        elif request.method == "PUT":
            user = update_user(request.body.get("user_id"), request.body)
            return Response({"user": user}, 200)
        elif request.method == "DELETE":
            delete_user(request.body.get("user_id"))
            return Response({"deleted": True}, 200)
    except Exception as e:
        return Response({"error": str(e)}, 500)


def handle_posts(request):
    """Handle post-related requests."""
    try:
        if request.method == "GET":
            post = get_post(request.body.get("post_id"))
            return Response({"post": post}, 200)
        elif request.method == "POST":
            post = create_post(request.body)
            return Response({"post": post}, 201)
        elif request.method == "PUT":
            post = update_post(request.body.get("post_id"), request.body)
            return Response({"post": post}, 200)
        elif request.method == "DELETE":
            delete_post(request.body.get("post_id"))
            return Response({"deleted": True}, 200)
    except Exception as e:
        return Response({"error": str(e)}, 500)


def handle_comments(request):
    """Handle comment-related requests."""
    try:
        if request.method == "GET":
            comments = get_comments(request.body.get("post_id"))
            return Response({"comments": comments}, 200)
        elif request.method == "POST":
            comment = add_comment(request.body)
            return Response({"comment": comment}, 201)
        elif request.method == "DELETE":
            delete_comment(request.body.get("comment_id"))
            return Response({"deleted": True}, 200)
    except Exception as e:
        return Response({"error": str(e)}, 500)

