"""Authentication service."""
import hashlib
import time

# Simulated user credentials store
_CREDENTIALS = {
    "admin": hashlib.sha256(b"admin123").hexdigest(),
    "alice": hashlib.sha256(b"password1").hexdigest(),
    "bob": hashlib.sha256(b"password2").hexdigest(),
}

# Simulated token store
_TOKENS = {}


def authenticate_user(username, password):
    """Authenticate a user and return a token."""
    if not username or not password:
        raise Exception("Username and password are required")

    if username not in _CREDENTIALS:
        raise Exception("Invalid credentials")

    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if _CREDENTIALS[username] != password_hash:
        raise Exception("Invalid credentials")

    token = hashlib.sha256(f"{username}:{time.time()}".encode()).hexdigest()
    _TOKENS[token] = {"username": username, "created_at": time.time()}
    return token


def verify_token(token):
    """Verify a token is valid."""
    if not token or token not in _TOKENS:
        raise Exception("Invalid or expired token")
    token_data = _TOKENS[token]
    if time.time() - token_data["created_at"] > 3600:
        del _TOKENS[token]
        raise Exception("Token has expired")
    return token_data["username"]

