"""User CRUD operations."""

# Simulated user database
_USERS = {
    1: {"id": 1, "username": "admin", "email": "admin@example.com", "role": "admin"},
    2: {"id": 2, "username": "alice", "email": "alice@example.com", "role": "user"},
    3: {"id": 3, "username": "bob", "email": "bob@example.com", "role": "user"},
}
_NEXT_ID = 4


def get_user(user_id):
    """Get a user by ID."""
    if user_id not in _USERS:
        raise Exception("User not found")
    return _USERS[user_id]


def create_user(data):
    """Create a new user."""
    global _NEXT_ID
    if not data.get("username"):
        raise Exception("Username is required")
    if not data.get("email"):
        raise Exception("Email is required")
    for user in _USERS.values():
        if user["username"] == data["username"]:
            raise Exception("Username already exists")
        if user["email"] == data["email"]:
            raise Exception("Email already exists")
    user = {
        "id": _NEXT_ID,
        "username": data["username"],
        "email": data["email"],
        "role": data.get("role", "user"),
    }
    _USERS[_NEXT_ID] = user
    _NEXT_ID += 1
    return user


def update_user(user_id, data):
    """Update an existing user."""
    if user_id not in _USERS:
        raise Exception("User not found")
    user = _USERS[user_id]
    if "username" in data:
        for uid, u in _USERS.items():
            if uid != user_id and u["username"] == data["username"]:
                raise Exception("Username already taken")
        user["username"] = data["username"]
    if "email" in data:
        user["email"] = data["email"]
    return user


def delete_user(user_id):
    """Delete a user."""
    if user_id not in _USERS:
        raise Exception("User not found")
    del _USERS[user_id]
    return True


def list_users():
    """List all users."""
    return list(_USERS.values())

