"""Middleware for rate limiting and request logging."""
import time

# Rate limiting state
_REQUEST_COUNTS = {}
_RATE_LIMIT = 100  # requests per minute
_WINDOW = 60  # seconds


def check_rate_limit(request):
    """Check if the request exceeds the rate limit."""
    client_ip = request.headers.get("X-Forwarded-For", "127.0.0.1")
    now = time.time()

    if client_ip not in _REQUEST_COUNTS:
        _REQUEST_COUNTS[client_ip] = []

    # Clean old entries
    _REQUEST_COUNTS[client_ip] = [
        t for t in _REQUEST_COUNTS[client_ip] if now - t < _WINDOW
    ]

    if len(_REQUEST_COUNTS[client_ip]) >= _RATE_LIMIT:
        raise Exception("Rate limit exceeded")

    _REQUEST_COUNTS[client_ip].append(now)


def log_request(request):
    """Log an incoming request."""
    try:
        timestamp = time.strftime("%Y-%m-%d %H:%M:%S")
        print(f"[{timestamp}] {request.method} {request.path}")
    except Exception as e:
        raise Exception("Failed to log request")

